import React from "react";
import Header from "./components/Header";
import HeroSection from "./components/HeroSection";
import MBTIOverview from "./components/MBTIOverview";
import MBTIDimensions from "./components/MBTIDimensions";
import ScientificView from "./components/ScientificView";
import RegisterMBTI from "./components/RegisterMBTI";
import StartTest from "./components/StartTest";
import Footer from "./components/Footer";

function App() {
  return (
    <div className="App">
      <Header/>
      <HeroSection/>
      <MBTIOverview />       
      <MBTIDimensions />
      <ScientificView />
      <RegisterMBTI />
      <StartTest />
      <Footer />
    </div>
  );
}

export default App;
